<?php
 namespace App\Controllers; use App\Models\UserModel; use CodeIgniter\API\ResponseTrait; use Firebase\JWT\JWT; class AuthController extends BaseController { use ResponseTrait; public function register() { $rules = [ 'name' => 'required|min_length[3]', 'email' => 'required|valid_email|is_unique[users.email]', 'password' => 'required|min_length[6]', 'role' => 'required|in_list[student,uploader]' ]; if (!$this->validate($rules)) { return $this->fail($this->validator->getErrors()); } $userModel = new UserModel(); $data = [ 'name' => $this->request->getVar('name'), 'email' => $this->request->getVar('email'), 'password_hash' => password_hash($this->request->getVar('password'), PASSWORD_DEFAULT), 'role' => $this->request->getVar('role') ]; if ($userModel->save($data)) { return $this->respondCreated(['message' => 'User registered successfully']); } return $this->failServerError('Could not register user.'); } public function login() { $userModel = new UserModel(); $email = $this->request->getVar('email'); $password = $this->request->getVar('password'); $user = $userModel->where('email', $email)->first(); if (is_null($user)) { return $this->failNotFound('Cannot find user with that email.'); } $pwd_verify = password_verify($password, $user['password_hash']); if (!$pwd_verify) { return $this->fail('Invalid password.', 401); } $key = getenv('JWT_SECRET'); if (!$key) { return $this->failServerError('JWT_SECRET key is not configured.'); } $iat = time(); $exp = $iat + 3600; $payload = [ 'iss' => 'asscat-api', 'aud' => 'asscat-client', 'iat' => $iat, 'exp' => $exp, 'uid' => $user['user_id'], 'email' => $user['email'], 'role' => $user['role'], ]; $token = JWT::encode($payload, $key, 'HS256'); return $this->respond([ 'message' => 'Login successful', 'token' => $token, 'role' => $user['role'] ], 200); } } 
